from __future__ import annotations
import argparse
from pathlib import Path
from banner_utils import Banner, repo_root, write_banner, validate, make_contact, MIDNIGHT, BLUEJAY, WHITE

def asset01():
    return [Banner(1,'classic-outlook-task-map','asset-01-task-map','Asset-01_Classic-Outlook-Task-Map_Title-Banner_v1.0','Classic Outlook Task Map','Choose the right Outlook action for common inbox work.',2100,405,'inbox decision flow','Classic Outlook Task Map branded title banner with an inbox decision-flow line icon on a Midnight background with Bluejay accent. The banner is a visual header only; keep the document title as live text outside the image.')]

def write_specs(root:Path,banners:list[Banner]):
    ad=root/'assets/title-banners/asset-01-task-map'; ad.mkdir(parents=True,exist_ok=True)
    b=banners[0]
    (ad/'README.md').write_text(f'''# Asset 01 — Classic Outlook Task Map Title Banner\n\nStatus: Production draft\n\nThis folder contains the editable SVG source and icon source for the Classic Outlook Task Map title banner. PNG exports are generated locally and in the GitHub Actions artifact, but are not committed because repository review does not support binary files.\n\n## macOS fresh-Terminal build\n\n```bash\ncd "$HOME" || exit 1\n\nREPO="$HOME/Documents/Classic-Outlook-Docs"\nVENV="$HOME/Documents/Classic-Outlook-Docs-venv"\n\nif [ ! -d "$REPO/.git" ]; then\n  git clone https://github.com/travis-true/Classic-Outlook-Docs.git "$REPO"\nfi\n\ncd "$REPO" || exit 1\n\ngit switch main\ngit pull --ff-only origin main\n\npython3 -m venv "$VENV"\nsource "$VENV/bin/activate"\n\npython3 -m pip install --upgrade pip\npython3 -m pip install -r "$REPO/build/requirements.txt"\n\npython3 "$REPO/build/build_title_banners.py" --asset 01\n\nBUILD_STATUS=$?\n\necho\necho "BUILD EXIT CODE: $BUILD_STATUS"\n\nif [ "$BUILD_STATUS" -ne 0 ]; then\n  echo "BUILD FAILED"\n  exit "$BUILD_STATUS"\nfi\n\nfind "$REPO/build/output/title-banners" -type f -print | sort\n\nopen "$REPO/build/output/title-banners"\n```\n''',encoding='utf-8')
    (ad/'Design-Spec.md').write_text(f'''# Design Spec — Asset 01 Classic Outlook Task Map\n\nStatus: Production draft\n\n- Size: {b.width} x {b.height} px\n- Background: Midnight `{MIDNIGHT}` solid fill\n- Accent: Bluejay `{BLUEJAY}` left rule and motif strokes\n- Title text: White `{WHITE}`\n- Motif: inbox decision flow\n- Logo: none inside banner\n- Accessibility note: keep the real document title as live Word text outside the image.\n''',encoding='utf-8')
    (ad/'Banner-Source-Spec.md').write_text(f'''# Banner Source Spec — Asset 01\n\nStatus: Production draft\n\n## Banner\n\n| File | Format | Dimensions | Title | Subtitle |\n|---|---:|---:|---|---|\n| {b.filename_base}.svg | Editable SVG | {b.width} x {b.height} | {b.title} | {b.subtitle} |\n| {b.filename_base}.png | PNG export generated by build, not committed | {b.width} x {b.height} | {b.title} | {b.subtitle} |\n\n## Icon source\n\n- `icons/inbox-decision-flow-icon.svg`\n''',encoding='utf-8')

def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--asset',default='01'); args=ap.parse_args()
    if str(args.asset).zfill(2)!='01': raise SystemExit('This branch builds asset 01 only.')
    root=repo_root(); banners=asset01(); write_specs(root,banners)
    for b in banners: write_banner(root,b)
    make_contact(root); validate(root,banners)
if __name__=='__main__': main()
